from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

# Configuration for Redis
REDIS_HOST = os.getenv('REDIS_HOST', 'your-redis-host')
REDIS_PORT = int(os.getenv('REDIS_PORT', 6379))
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD', 'your-redis-password')
REDIS_SSL = True

# Establish connection to Redis
redis_client = redis.StrictRedis(
    host=REDIS_HOST,
    port=REDIS_PORT,
    password=REDIS_PASSWORD,
    ssl=REDIS_SSL,
    decode_responses=True
)

# Endpoint to store sensitive data
@app.route('/store', methods=['POST'])
def store_data():
    data = request.json
    key = data.get('key')
    value = data.get('value')
    ttl = data.get('ttl', 3600)  # Default TTL is 1 hour

    if not key or not value:
        return jsonify({'error': 'Key and value are required'}), 400

    redis_client.setex(key, ttl, value)
    return jsonify({'message': 'Data stored successfully'}), 200

# Endpoint to retrieve sensitive data
@app.route('/retrieve/<key>', methods=['GET'])
def retrieve_data(key):
    value = redis_client.get(key)
    if value is None:
        return jsonify({'error': 'Key not found'}), 404
    return jsonify({'value': value}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)